import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Container, Flex, Section, Heading } from "@radix-ui/themes";
import './App.css';
import { useState } from "react";
import { useMouseMove, useValue } from "react-ui-animate";
import Navigation from "./Navigation";
import About from "./aboutme.js";
import Links from "./links.js";
import Experience from "./Experience.js";
import Projects from "./Projects.js";


function App() {

  const [cursorState, setCursorState] = useState({
    xPercent: 0,
    yPercent: 0
  });

  let [counter, setCounter] = useState(0);

  const [backgroundColors, setBackgroundColors] = useState({
    primary: "#85035e",
    secondary: "#660416"
  })

  const windowWidth = window.innerWidth;
  const windowHeight = window.innerHeight;

  const x = useValue(0);
  const y = useValue(0);

  useMouseMove(({ mouseX, mouseY }) => {
    x.value = mouseX;
    y.value = mouseY;
    let xPercent = x.value.value / windowWidth;
    let yPercent = y.value.value / windowHeight;
    xPercent *= 100;
    yPercent *= 100;
    setCursorState({
      xPercent: xPercent.toFixed(0),
      yPercent: yPercent.toFixed(0)
    });
  });

  const handleClick = () => {
    setCounter(counter += 1);

    if(counter % 3 === 0){
      setBackgroundColors({
        primary: "#85035e",
        secondary: "#660416"
      })
    } else if(counter % 2 === 0){
      setBackgroundColors({
        primary: "rgb(104, 73, 251)",
        secondary: "rgb(19, 76, 49)"
      })
    } else if(counter % 5 === 0){
      setBackgroundColors({
        primary: "rgb(2, 166, 95)",
        secondary: "rgb(97, 89, 20)"
      })
    } else {
      setBackgroundColors({
        primary: "rgb(99, 34, 62)",
        secondary: "rgb(50, 123, 209)"
      })
    }

    // else {
    //   let primaryR = Math.floor(Math.random() * 255);
    //   let primaryG = Math.floor(Math.random() * 255);
    //   let primaryB = Math.floor(Math.random() * 255);

    //   let secondaryR = Math.floor(Math.random() * 255);
    //   let secondaryG = Math.floor(Math.random() * 255);
    //   let secondaryB = Math.floor(Math.random() * 255);
    //   setBackgroundColors({
    //     primary: `rgb(${primaryR}, ${primaryG}, ${primaryB})`,
    //     secondary: `rgb(${secondaryR}, ${secondaryG}, ${secondaryB})`
    //   })
    // }

    console.log(counter);
  }

  return (
    <Theme style={{ background: `radial-gradient(circle at ${cursorState.xPercent}% ${cursorState.yPercent}%, ${backgroundColors.primary} 0%, ${backgroundColors.secondary} 80%)` }} id="theme_element" scaling="90%" grayColor="mauve" accentColor="teal" panelBackground="translucent" appearance="dark">
      {/* <ThemePanel /> */}
      <Container size="5">
        <Flex gap="4" direction="row" justify="between">
          <Section width="50%" height="100vh" id = "left_page" position="sticky" top="0">
            <Flex justify="between" height="100%" direction="column">
              <Flex gap="4" direction="column">
                <Heading mt="6" size="9">Ted Fawke</Heading>
                <Heading weight="medium" size="6">Full Stack Web Developer</Heading>
                <Heading className="my_promise" weight="light" size="4" style={{ color: "rgba(255, 255, 255, 0.73)" }}>The industrial revolution and its consequences have been a disaster for the human race.</Heading>
              </Flex>
              <Navigation />
              <Links />
            </Flex>
          </Section>
          <Section width="50%">
            <Flex gap="4" direction="column">
              <About shakeIt={handleClick} />
              {/* <Experience /> */}
              <Projects />
            </Flex>
          </Section>
        </Flex>
      </Container>
    </Theme>
  );
}

export default App;
